     1→/*
     2→ * ESP32 Single Rotary Encoder Reader
     3→ * ====================================
     4→ * 대상 엔코더: Autonics E40H8-1024-3-T-24
     5→ *   - PPR  : 1024 pulses/rev
     6→ *   - 출력  : Totem-pole, 12~24VDC
     7→ *   - 배선  : BLACK=A, WHITE=B, ORANGE=Z, BROWN=+V, BLUE=0V, SHIELD=FG
     8→ *
     9→ * 해상도 : 1024 PPR × 4배체배 = 4096 counts/rev
    10→ *
    11→ * 통신 포트 (동시 동작):
    12→ *   - Serial  : USB CDC (Arduino Nano ESP32 기본)
    13→ *   - Serial1 : GPIO16(TX) / GPIO17(RX) 하드웨어 UART
    14→ *
    15→ * 명령어 (시리얼):
    16→ *   ZERO        - 현재 카운트를 0으로 리셋 (NVS 저장 안함)
    17→ *   SETHOME     - 현재 위치를 절대 원점으로 저장 (NVS 저장)
    18→ *   SAVE n      - 현재 위치를 n번에 저장 (1~100)
    19→ *   GET n       - n번 저장 위치 조회
    20→ *   GETALL      - 모든 저장 위치 조회
    21→ *   DELETE n    - n번 저장 위치 삭제
    22→ *   CLEAR       - 모든 저장 위치 삭제
    23→ *   ZUSE        - Z채널 보정 활성화
    24→ *   ZNUSE       - Z채널 보정 비활성화
    25→ *   TOL n       - 위치 허용 오차 설정 (카운트)
    26→ *   INFO        - 시스템 정보 출력
    27→ *   STATUS / ?  - 현재 상태 즉시 출력
    28→ *
    29→ * 작성일: 2026-02-25
    30→ */
    31→
    32→#include <Arduino.h>
    33→#include <Preferences.h>
    34→
    35→// ============================================================
    36→// 핀 설정
    37→// ============================================================
    38→#define ENC_PIN_A   34    // OUT A (BLACK)
    39→#define ENC_PIN_B   35    // OUT B (WHITE)
    40→#define ENC_PIN_Z   32    // OUT Z (ORANGE) - 인덱스 펄스
    41→
    42→// GPIO UART 핀 (Serial1) - USB CDC 끊김 대비 하드웨어 시리얼
    43→#define UART_TX_PIN 16    // GPIO16 = TX → PC RX 연결
    44→#define UART_RX_PIN 17    // GPIO17 = RX → PC TX 연결
    45→
    46→// ============================================================
    47→// 엔코더 설정
    48→// ============================================================
    49→#define ENCODER_PPR         1024    // Autonics E40H8-1024-3-T-24 PPR
    50→#define QUADRATURE_MULT     4       // 4배체배 (A+B 모두 CHANGE)
    51→#define COUNTS_PER_REV      (ENCODER_PPR * QUADRATURE_MULT)  // 4096 counts/rev
    52→
    53→// ============================================================
    54→// 통신 설정
    55→// ============================================================
    56→#define SERIAL_BAUD         921600  // 고속 통신
    57→#define UPDATE_INTERVAL_MS  10      // 업데이트 주기 (10ms = 100Hz)
    58→
    59→// ============================================================
    60→// 위치 저장 설정
    61→// ============================================================
    62→#define MAX_POSITIONS   100
    63→
    64→// ============================================================
    65→// 두 포트 동시 출력 헬퍼 (USB CDC + UART)
    66→// ============================================================
    67→template<typename T>
    68→void comPrint(T v)          { Serial.print(v);    Serial1.print(v);    }
    69→template<typename T, typename F>
    70→void comPrint(T v, F f)     { Serial.print(v,f);  Serial1.print(v,f);  }
    71→template<typename T>
    72→void comPrintln(T v)        { Serial.println(v);  Serial1.println(v);  }
    73→template<typename T, typename F>
    74→void comPrintln(T v, F f)   { Serial.println(v,f);Serial1.println(v,f);}
    75→void comPrintln()           { Serial.println();   Serial1.println();   }
    76→
    77→// ============================================================
    78→// 쿼드러처 디코딩 테이블
    79→// state = (B<<1)|A
    80→// 순방향(CW): 00→01→11→10→00 = +1
    81→// 역방향(CCW): 00→10→11→01→00 = -1
    82→// ============================================================
    83→const int8_t QUAD_TABLE[4][4] = {
    84→  {  0, +1, -1,  0 },
    85→  { -1,  0,  0, +1 },
    86→  { +1,  0,  0, -1 },
    87→  {  0, -1, +1,  0 }
    88→};
    89→
    90→// ============================================================
    91→// 글로벌 변수
    92→// ============================================================
    93→volatile int32_t enc_count      = 0;
    94→volatile uint8_t enc_last_state = 0;
    95→volatile bool    z_pulse_flag   = false;
    96→
    97→int32_t enc_offset          = 0;
    98→bool    use_z_correction    = false;
    99→int     position_tolerance  = 5;
   100→
   101→int32_t saved_positions[MAX_POSITIONS];
   102→
   103→unsigned long last_update_time = 0;
   104→unsigned long start_time       = 0;
   105→
   106→// 각 포트별 수신 버퍼
   107→String buf_usb  = "";  // Serial  (USB CDC)
   108→String buf_uart = "";  // Serial1 (GPIO UART)
   109→
   110→Preferences preferences;
   111→
   112→// ============================================================
   113→// 인터럽트 핸들러 - A/B 쿼드러처 (4배체배)
   114→// ============================================================
   115→void IRAM_ATTR enc_ab_isr() {
   116→  uint8_t a = digitalRead(ENC_PIN_A);
   117→  uint8_t b = digitalRead(ENC_PIN_B);
   118→  uint8_t cur = (b << 1) | a;
   119→  enc_count += QUAD_TABLE[enc_last_state][cur];
   120→  enc_last_state = cur;
   121→}
   122→
   123→// ============================================================
   124→// 인터럽트 핸들러 - Z 인덱스 펄스 (RISING)
   125→// ============================================================
   126→void IRAM_ATTR enc_z_isr() {
   127→  if (use_z_correction) {
   128→    int32_t remainder = enc_count % COUNTS_PER_REV;
   129→    if (remainder > COUNTS_PER_REV / 2)
   130→      enc_count += (COUNTS_PER_REV - remainder);
   131→    else
   132→      enc_count -= remainder;
   133→  }
   134→  z_pulse_flag = true;
   135→}
   136→
   137→// ============================================================
   138→// 절대 카운트 (오프셋 적용)
   139→// ============================================================
   140→inline int32_t getAbsCount() {
   141→  noInterrupts();
   142→  int32_t c = enc_count;
   143→  interrupts();
   144→  return c - enc_offset;
   145→}
   146→
   147→// ============================================================
   148→// 카운트 → 각도 (0~360도)
   149→// ============================================================
   150→float countToDegree(int32_t count) {
   151→  int32_t m = ((count % COUNTS_PER_REV) + COUNTS_PER_REV) % COUNTS_PER_REV;
   152→  return (float)m / COUNTS_PER_REV * 360.0f;
   153→}
   154→
   155→// ============================================================
   156→// NVS 저장/불러오기
   157→// ============================================================
   158→void saveOffset() {
   159→  preferences.begin("enc", false);
   160→  preferences.putInt("offset", enc_offset);
   161→  preferences.end();
   162→}
   163→
   164→void loadOffset() {
   165→  preferences.begin("enc", true);
   166→  enc_offset = preferences.getInt("offset", 0);
   167→  preferences.end();
   168→}
   169→
   170→void savePositionNVS(int idx) {
   171→  preferences.begin("enc", false);
   172→  String key = "p" + String(idx + 1);
   173→  preferences.putInt(key.c_str(), saved_positions[idx]);
   174→  preferences.end();
   175→}
   176→
   177→void loadAllPositions() {
   178→  preferences.begin("enc", true);
   179→  for (int i = 0; i < MAX_POSITIONS; i++) {
   180→    String key = "p" + String(i + 1);
   181→    saved_positions[i] = preferences.getInt(key.c_str(), INT32_MIN);
   182→  }
   183→  preferences.end();
   184→}
   185→
   186→// ============================================================
   187→// 엔코더 데이터 JSON 전송
   188→// ============================================================
   189→void sendEncoderData() {
   190→  int32_t abs_cnt = getAbsCount();
   191→  // 선형 각도 (modulo 없음): ZERO 기준 양/음 방향 모두 정확히 표현
   192→  float   deg     = (float)abs_cnt / COUNTS_PER_REV * 360.0f;
   193→  unsigned long ts = millis() - start_time;
   194→
   195→  comPrint("{\"t\":");
   196→  comPrint(ts);
   197→  comPrint(",\"cnt\":");
   198→  comPrint(abs_cnt);
   199→  comPrint(",\"deg\":");
   200→  comPrint(deg, 2);
   201→  if (z_pulse_flag) {
   202→    comPrint(",\"z\":true");
   203→    z_pulse_flag = false;
   204→  }
   205→  comPrintln(",\"ok\":true}");
   206→}
   207→
   208→// ============================================================
   209→// 저장 위치 JSON 전송
   210→// ============================================================
   211→void sendPositionInfo(int pos) {
   212→  if (pos < 1 || pos > MAX_POSITIONS) return;
   213→  int  idx = pos - 1;
   214→  bool has = (saved_positions[idx] != INT32_MIN);
   215→
   216→  comPrint("{\"cmd\":\"GET\",\"pos\":");
   217→  comPrint(pos);
   218→  if (has) {
   219→    float deg = countToDegree(saved_positions[idx]);
   220→    comPrint(",\"cnt\":");
   221→    comPrint(saved_positions[idx]);
   222→    comPrint(",\"deg\":");
   223→    comPrint(deg, 2);
   224→    comPrintln(",\"ok\":true}");
   225→  } else {
   226→    comPrintln(",\"ok\":false,\"error\":\"empty\"}");
   227→  }
   228→}
   229→
   230→void sendAllPositions() {
   231→  comPrint("{\"cmd\":\"GETALL\",\"data\":[");
   232→  bool first = true;
   233→  for (int i = 0; i < MAX_POSITIONS; i++) {
   234→    if (saved_positions[i] == INT32_MIN) continue;
   235→    if (!first) comPrint(",");
   236→    first = false;
   237→    float deg = countToDegree(saved_positions[i]);
   238→    comPrint("{\"pos\":");
   239→    comPrint(i + 1);
   240→    comPrint(",\"cnt\":");
   241→    comPrint(saved_positions[i]);
   242→    comPrint(",\"deg\":");
   243→    comPrint(deg, 2);
   244→    comPrint("}");
   245→  }
   246→  comPrintln("],\"ok\":true}");
   247→}
   248→
   249→// ============================================================
   250→// 시리얼 명령 처리
   251→// ============================================================
   252→void processCommand(String cmd) {
   253→  cmd.trim();
   254→  cmd.toUpperCase();
   255→
   256→  // ZERO: 카운트 리셋
   257→  if (cmd == "ZERO") {
   258→    noInterrupts();
   259→    enc_count = 0;
   260→    interrupts();
   261→    enc_offset = 0;
   262→    comPrintln("{\"cmd\":\"ZERO\",\"ok\":true}");
   263→  }
   264→
   265→  // SETHOME: 현재 위치를 절대 원점으로 NVS 저장
   266→  else if (cmd == "SETHOME") {
   267→    noInterrupts();
   268→    enc_offset = enc_count;
   269→    interrupts();
   270→    saveOffset();
   271→    comPrint("{\"cmd\":\"SETHOME\",\"offset\":");
   272→    comPrint(enc_offset);
   273→    comPrintln(",\"ok\":true}");
   274→  }
   275→
   276→  // SAVE n
   277→  else if (cmd.startsWith("SAVE")) {
   278→    String sub = cmd.substring(4);
   279→    sub.trim();
   280→    int n = sub.toInt();
   281→    if (n >= 1 && n <= MAX_POSITIONS) {
   282→      int idx = n - 1;
   283→      saved_positions[idx] = getAbsCount();
   284→      savePositionNVS(idx);
   285→      float deg = countToDegree(saved_positions[idx]);
   286→      comPrint("{\"cmd\":\"SAVE\",\"pos\":");
   287→      comPrint(n);
   288→      comPrint(",\"cnt\":");
   289→      comPrint(saved_positions[idx]);
   290→      comPrint(",\"deg\":");
   291→      comPrint(deg, 2);
   292→      comPrintln(",\"ok\":true}");
   293→    } else {
   294→      comPrintln("{\"cmd\":\"SAVE\",\"ok\":false,\"error\":\"Invalid pos (1-100)\"}");
   295→    }
   296→  }
   297→
   298→  // GET n
   299→  else if (cmd.startsWith("GET ")) {
   300→    int n = cmd.substring(4).toInt();
   301→    sendPositionInfo(n);
   302→  }
   303→
   304→  // GETALL
   305→  else if (cmd == "GETALL") {
   306→    sendAllPositions();
   307→  }
   308→
   309→  // DELETE n
   310→  else if (cmd.startsWith("DELETE ")) {
   311→    int n = cmd.substring(7).toInt();
   312→    if (n >= 1 && n <= MAX_POSITIONS) {
   313→      int idx = n - 1;
   314→      saved_positions[idx] = INT32_MIN;
   315→      preferences.begin("enc", false);
   316→      String key = "p" + String(n);
   317→      preferences.putInt(key.c_str(), INT32_MIN);
   318→      preferences.end();
   319→      comPrint("{\"cmd\":\"DELETE\",\"pos\":");
   320→      comPrint(n);
   321→      comPrintln(",\"ok\":true}");
   322→    } else {
   323→      comPrintln("{\"cmd\":\"DELETE\",\"ok\":false,\"error\":\"Invalid pos\"}");
   324→    }
   325→  }
   326→
   327→  // CLEAR
   328→  else if (cmd == "CLEAR") {
   329→    preferences.begin("enc", false);
   330→    for (int i = 0; i < MAX_POSITIONS; i++) {
   331→      saved_positions[i] = INT32_MIN;
   332→      String key = "p" + String(i + 1);
   333→      preferences.putInt(key.c_str(), INT32_MIN);
   334→    }
   335→    preferences.end();
   336→    comPrintln("{\"cmd\":\"CLEAR\",\"ok\":true}");
   337→  }
   338→
   339→  // ZUSE / ZNUSE
   340→  else if (cmd == "ZUSE") {
   341→    use_z_correction = true;
   342→    comPrintln("{\"cmd\":\"ZUSE\",\"z_correction\":true,\"ok\":true}");
   343→  }
   344→  else if (cmd == "ZNUSE") {
   345→    use_z_correction = false;
   346→    comPrintln("{\"cmd\":\"ZNUSE\",\"z_correction\":false,\"ok\":true}");
   347→  }
   348→
   349→  // TOL n
   350→  else if (cmd.startsWith("TOL ")) {
   351→    int tol = cmd.substring(4).toInt();
   352→    if (tol >= 1 && tol <= 1000) {
   353→      position_tolerance = tol;
   354→      float tol_deg = (float)tol / COUNTS_PER_REV * 360.0f;
   355→      comPrint("{\"cmd\":\"TOL\",\"cnt\":");
   356→      comPrint(tol);
   357→      comPrint(",\"deg\":");
   358→      comPrint(tol_deg, 3);
   359→      comPrintln(",\"ok\":true}");
   360→    } else {
   361→      comPrintln("{\"cmd\":\"TOL\",\"ok\":false,\"error\":\"Invalid (1-1000)\"}");
   362→    }
   363→  }
   364→
   365→  // STATUS
   366→  else if (cmd == "STATUS" || cmd == "?") {
   367→    sendEncoderData();
   368→  }
   369→
   370→  // INFO
   371→  else if (cmd == "INFO") {
   372→    comPrint("{\"model\":\"E40H8-1024-3-T-24\"");
   373→    comPrint(",\"ppr\":");
   374→    comPrint(ENCODER_PPR);
   375→    comPrint(",\"cpr\":");
   376→    comPrint(COUNTS_PER_REV);
   377→    comPrint(",\"hz\":");
   378→    comPrint(1000 / UPDATE_INTERVAL_MS);
   379→    comPrint(",\"baud\":");
   380→    comPrint(SERIAL_BAUD);
   381→    comPrint(",\"offset\":");
   382→    comPrint(enc_offset);
   383→    comPrint(",\"z_correction\":");
   384→    comPrint(use_z_correction ? "true" : "false");
   385→    comPrint(",\"tolerance_cnt\":");
   386→    comPrint(position_tolerance);
   387→    comPrint(",\"uart_tx\":");
   388→    comPrint(UART_TX_PIN);
   389→    comPrint(",\"uart_rx\":");
   390→    comPrint(UART_RX_PIN);
   391→    comPrintln(",\"ok\":true}");
   392→  }
   393→
   394→  // 알 수 없는 명령
   395→  else {
   396→    comPrint("{\"cmd\":\"UNKNOWN\",\"input\":\"");
   397→    comPrint(cmd);
   398→    comPrintln("\",\"ok\":false}");
   399→  }
   400→}
   401→
   402→// ============================================================
   403→// 수신 버퍼 처리 (공통)
   404→// ============================================================
   405→void processBuf(char c, String& buf) {
   406→  if (c == '\n' || c == '\r') {
   407→    if (buf.length() > 0) {
   408→      processCommand(buf);
   409→      buf = "";
   410→    }
   411→  } else {
   412→    buf += c;
   413→    if (buf.length() > 64) buf = "";
   414→  }
   415→}
   416→
   417→// ============================================================
   418→// setup
   419→// ============================================================
   420→void setup() {
   421→  // USB CDC 시리얼
   422→  Serial.begin(SERIAL_BAUD);
   423→  while (!Serial) { delay(10); }
   424→
   425→  // GPIO UART 시리얼 (TX=16, RX=17)
   426→  Serial1.begin(SERIAL_BAUD, SERIAL_8N1, UART_RX_PIN, UART_TX_PIN);
   427→
   428→  // 핀 설정 (토템폴 출력 → 외부 풀업 없이 INPUT 사용)
   429→  pinMode(ENC_PIN_A, INPUT);
   430→  pinMode(ENC_PIN_B, INPUT);
   431→  pinMode(ENC_PIN_Z, INPUT);
   432→
   433→  // NVS에서 저장값 복원
   434→  loadOffset();
   435→  loadAllPositions();
   436→
   437→  // 초기 AB 상태 읽기
   438→  enc_last_state = (digitalRead(ENC_PIN_B) << 1) | digitalRead(ENC_PIN_A);
   439→
   440→  // 인터럽트 설정
   441→  attachInterrupt(digitalPinToInterrupt(ENC_PIN_A), enc_ab_isr, CHANGE);
   442→  attachInterrupt(digitalPinToInterrupt(ENC_PIN_B), enc_ab_isr, CHANGE);
   443→  // Z채널 인터럽트 비활성화: 스위치 각도 검사에서 Z 보정 불필요 + 노이즈로 카운트 오류 발생
   444→  // attachInterrupt(digitalPinToInterrupt(ENC_PIN_Z), enc_z_isr,  RISING);
   445→
   446→  start_time       = millis();
   447→  last_update_time = start_time;
   448→
   449→  // 시작 메시지
   450→  comPrint("{\"msg\":\"E40H8-1024-3-T-24 Ready\"");
   451→  comPrint(",\"ppr\":");
   452→  comPrint(ENCODER_PPR);
   453→  comPrint(",\"cpr\":");
   454→  comPrint(COUNTS_PER_REV);
   455→  comPrint(",\"offset\":");
   456→  comPrint(enc_offset);
   457→  comPrint(",\"uart_tx\":");
   458→  comPrint(UART_TX_PIN);
   459→  comPrint(",\"uart_rx\":");
   460→  comPrint(UART_RX_PIN);
   461→  comPrintln(",\"ok\":true}");
   462→}
   463→
   464→// ============================================================
   465→// loop
   466→// ============================================================
   467→void loop() {
   468→  unsigned long now = millis();
   469→
   470→  // 주기적 데이터 전송
   471→  if (now - last_update_time >= UPDATE_INTERVAL_MS) {
   472→    last_update_time = now;
   473→    sendEncoderData();
   474→  }
   475→
   476→  // USB CDC 수신
   477→  while (Serial.available() > 0) {
   478→    processBuf((char)Serial.read(), buf_usb);
   479→  }
   480→
   481→  // GPIO UART 수신
   482→  while (Serial1.available() > 0) {
   483→    processBuf((char)Serial1.read(), buf_uart);
   484→  }
   485→}
